module top_module(
  input clk_in,
  input reset,
  input [7:0] divider,
  output reg clk_out
);reg [7:0] obf_count = 0;

  always @(posedge clk_in or posedge reset) begin
    if (reset) begin
      clk_out <= 0;
      obf_count <= 0;
    end else begin
      obf_count <= obf_count + 1;
      if (obf_count == divider) begin
        clk_out <= ~clk_out;
        obf_count <= 0;
      end
    end
  end

endmodule
